create table dirkspzm32.pzm_lohnarten_erp_bew (
    lz_id                number(*, 0) not null enable,
    lz_bew_id            varchar2(10 char) not null enable,
    lz_bew_einheit       varchar2(10 char) default 'HH24' not null enable,
    lz_bew_beschreibung  varchar2(30 char),
    lz_bew_loa           varchar2(10 char),
    created_date         date default sysdate not null enable,
    created_login_id     number(*, 0) default - 1 not null enable,
    last_change_date     date,
    last_change_login_id number(*, 0)
);

alter table dirkspzm32.pzm_lohnarten_erp_bew
    add constraint pk_lz_bew_id primary key ( lz_id,
                                              lz_bew_id )
        using index enable;


